/**
 * Unit tests for instructions-loaded-dispatcher.ts
 *
 * #2475: the REAL CC InstructionsLoaded payload is single-file:
 * { file_path, memory_type, load_reason }. Fixtures here reflect that real
 * shape — the previous fabricated `files_loaded` array is gone.
 *
 * The dispatcher runs 2 per-file handlers and surfaces findings ONLY via
 * systemMessage (never additionalContext — output-guard strips it for this
 * event).
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';
import { mockCommonBasic } from '../fixtures/mock-common.js';

// Mock both per-file handlers so dispatcher logic is tested in isolation
const mockTokenBudget = vi.fn();
const mockSmartSuggestions = vi.fn();

vi.mock('../../instructions-loaded/token-budget-tracker.js', () => ({
  tokenBudgetTracker: (...args: unknown[]) => mockTokenBudget(...args),
}));
vi.mock('../../instructions-loaded/smart-suggestions.js', () => ({
  smartRuleSuggestions: (...args: unknown[]) => mockSmartSuggestions(...args),
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { instructionsLoadedDispatcher } from '../../instructions-loaded/instructions-loaded-dispatcher.js';
import { createTestContext } from '../fixtures/test-context.js';

/** Build the REAL single-file InstructionsLoaded payload. */
function makeInput(overrides: Record<string, unknown> = {}): HookInput {
  return {
    hook_event: 'InstructionsLoaded',
    tool_name: 'InstructionsLoaded',
    session_id: 'test-session',
    project_dir: '/test/project',
    tool_input: {},
    file_path: '/test/project/CLAUDE.md',
    memory_type: 'project',
    load_reason: 'startup',
    ...overrides,
  } as unknown as HookInput;
}

let testCtx: ReturnType<typeof createTestContext>;
beforeEach(() => {
  testCtx = createTestContext();
  vi.clearAllMocks();
  // Default: both handlers silent
  mockTokenBudget.mockReturnValue(null);
  mockSmartSuggestions.mockReturnValue(null);
});

describe('instructionsLoadedDispatcher', () => {
  describe('payload guard — real single-file shape', () => {
    test('returns silent success when file_path is absent', () => {
      const result = instructionsLoadedDispatcher(makeInput({ file_path: undefined }), testCtx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(mockTokenBudget).not.toHaveBeenCalled();
      expect(mockSmartSuggestions).not.toHaveBeenCalled();
    });

    test('returns silent success when file_path is empty', () => {
      const result = instructionsLoadedDispatcher(makeInput({ file_path: '' }), testCtx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(mockTokenBudget).not.toHaveBeenCalled();
    });

    test('returns silent success when file_path is not a string', () => {
      const result = instructionsLoadedDispatcher(makeInput({ file_path: 42 }), testCtx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(mockTokenBudget).not.toHaveBeenCalled();
    });

    test('ignores a legacy fabricated files_loaded array without file_path', () => {
      const result = instructionsLoadedDispatcher(
        makeInput({ file_path: undefined, files_loaded: [{ path: '/x/CLAUDE.md', byte_size: 10 }] }),
        testCtx
      );
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(mockTokenBudget).not.toHaveBeenCalled();
    });
  });

  describe('per-file handler dispatch', () => {
    test('calls both per-file handlers exactly once with the typed input', () => {
      const input = makeInput();
      instructionsLoadedDispatcher(input, testCtx);
      expect(mockTokenBudget).toHaveBeenCalledOnce();
      expect(mockSmartSuggestions).toHaveBeenCalledOnce();
      expect(mockTokenBudget).toHaveBeenCalledWith(input);
      expect(mockSmartSuggestions).toHaveBeenCalledWith(input);
    });

    test('memory_type and load_reason are optional', () => {
      const input = makeInput({ memory_type: undefined, load_reason: undefined });
      const result = instructionsLoadedDispatcher(input, testCtx);
      expect(result.continue).toBe(true);
      expect(mockTokenBudget).toHaveBeenCalledOnce();
    });
  });

  describe('output contract — systemMessage only, never additionalContext', () => {
    test('returns silent success when both handlers are silent', () => {
      const result = instructionsLoadedDispatcher(makeInput(), testCtx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.systemMessage).toBeUndefined();
      expect(result.hookSpecificOutput).toBeUndefined();
    });

    test('surfaces a single handler finding via systemMessage', () => {
      mockTokenBudget.mockReturnValue('[Instruction Budget] warning');
      const result = instructionsLoadedDispatcher(makeInput(), testCtx);
      expect(result.continue).toBe(true);
      expect(result.systemMessage).toBe('[Instruction Budget] warning');
      expect(result.hookSpecificOutput).toBeUndefined();
    });

    test('joins multiple handler findings with newline', () => {
      mockTokenBudget.mockReturnValue('Budget output');
      mockSmartSuggestions.mockReturnValue('Suggestion output');
      const result = instructionsLoadedDispatcher(makeInput(), testCtx);
      expect(result.systemMessage).toBe('Budget output\nSuggestion output');
    });

    test('NEVER emits additionalContext (output-guard strips it for this event)', () => {
      mockTokenBudget.mockReturnValue('Budget output');
      mockSmartSuggestions.mockReturnValue('Suggestion output');
      const result = instructionsLoadedDispatcher(makeInput(), testCtx);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });
  });

  describe('handler error isolation', () => {
    test('continues running remaining handlers when one throws', () => {
      mockTokenBudget.mockImplementation(() => { throw new Error('budget exploded'); });
      mockSmartSuggestions.mockReturnValue('Suggestion output');
      const result = instructionsLoadedDispatcher(makeInput(), testCtx);
      expect(result.continue).toBe(true);
      expect(result.systemMessage).toBe('Suggestion output');
    });

    test('returns silent success when all handlers throw', () => {
      const boom = () => { throw new Error('boom'); };
      mockTokenBudget.mockImplementation(boom);
      mockSmartSuggestions.mockImplementation(boom);
      expect(() => instructionsLoadedDispatcher(makeInput(), testCtx)).not.toThrow();
      const result = instructionsLoadedDispatcher(makeInput(), testCtx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });
  });
});
